parameters.jsCode:
// 1) Valida se custom_fields existe e é um array
if (!items[0].json.custom_fields || !Array.isArray(items[0].json.custom_fields)) {
  throw new Error("O array custom_fields não existe.");
}

// 2) Procura o campo "Onde Conheceu?" no array custom_fields
const campo = items[0].json.custom_fields.find(cf => cf.id === 
"ae1e1e90-c866-4c24-af40-ecbeff2e7a22");

// 3) Valida se o campo foi encontrado
if (!campo) {
  throw new Error("O campo 'Onde Conheceu?' não foi encontrado em custom_fields.");
}

// 4) Garante que o campo possui options configuradas em type_config
const options = campo.type_config?.options;
if (!options || !Array.isArray(options)) {
  throw new Error("O campo não possui opções configuradas em type_config.options");
}

// 5) Encontra a opção cujo orderindex corresponde ao valor selecionado
const selecionada = options.find(opt => opt.orderindex === campo.value);
if (!selecionada) {
  throw new Error(`Nenhuma opção encontrada para o valor ${campo.value}`);
}

// 6) Utiliza regex para capturar o conteúdo dentro dos colchetes
const regex = /\[([^\]]+)\]/;
const match = selecionada.name.match(regex);
const tag = match ? match[1] : "";

// 7) Retorna os valores extraídos
return [
  {
    json: {
      customFieldValue: campo.value,
      customFieldName: selecionada.name,
      tag: tag
    }
  }
];

